from langchain.retrievers import ContextualCompressionRetriever

# Using Cohere reranker
cohere_reranker = CohereRerank()
rerank_retriever = ContextualCompressionRetriever(
    base_retriever, cohere_reranker
)

rerank_stats = {'promoted': 0, 'total': 0}
def track_reranking(query):
    docs = rerank_retriever.get_relevant_documents(query)
    rerank_stats['total'] += 1
    if len(docs) > 0 and docs[0].metadata.get('score', 0) > 0.8:
        rerank_stats['promoted'] += 1
    hit_rate = rerank_stats['promoted'] / rerank_stats['total']
    if hit_rate < 0.6:
        print(f'⚠️ Reranker hit rate low: {hit_rate:.1%}')
    return docs
